import { Pipe, PipeTransform } from '@angular/core';
import { CronInterpreter } from '@shared/utils';

@Pipe({
  name: 'cronToHuman',
  standalone: true,
})
export class CronToHumanPipe implements PipeTransform {
  /**
   * @param value El string cron (ej: '0 0 * * 5')
   * @param type 'frequency' | 'detail' | 'full'
   */
  transform(
    value: string | undefined | null,
    type: 'frequency' | 'detail' | 'full' = 'full',
  ): string {
    if (!value) return '';

    const result = CronInterpreter.parse(value);

    if (type === 'frequency') return result.frequency;
    if (type === 'detail') return result.detail;

    return `${result.frequency}: ${result.detail}`;
  }
}

import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  name: 'fileSize',
})
export class FileSizePipe implements PipeTransform {
  private readonly units = ['Bytes', 'KB', 'MB', 'GB', 'TB'];

  transform(bytes?: number, precision = 2): string {
    if (!bytes) return '0 Bytes';

    if (isNaN(parseFloat(String(bytes))) || !isFinite(bytes) || bytes <= 0) {
      return '0 Bytes';
    }

    let unitIndex = 0;
    while (bytes >= 1024 && unitIndex < this.units.length - 1) {
      bytes /= 1024;
      unitIndex++;
    }

    return `${bytes.toFixed(precision)} ${this.units[unitIndex]}`;
  }
}

import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  name: 'phone',
})
export class PhonePipe implements PipeTransform {
  transform(value: string): string {
    const cleaned = value.replace(/\D/g, '');
    const match = cleaned.match(/^(\d{3})(\d{3})(\d{4})$/);
    if (match) {
      return `(${match[1]}) ${match[2]}-${match[3]}`;
    }
    return value;
  }
}

import { Pipe, PipeTransform } from '@angular/core';
import { UserRoleEnum } from '@nex-house/enums';

@Pipe({
  name: 'role',
})
export class RolePipe implements PipeTransform {
  transform(value: string | undefined) {
    if (value === UserRoleEnum.ADMIN) return 'Administrador';
    if (value === UserRoleEnum.RESIDENT) return 'Residente';
    if (value === UserRoleEnum.SUPER_ADMIN) return 'ROOT';

    return 'Unknown';
  }
}

