import {
  setError,
  setLoaded,
  setLoading,
  withCallState,
  withDevtools,
  withReset,
} from '@angular-architects/ngrx-toolkit';
import { computed, effect, inject } from '@angular/core';
import { APP_CONSTANTS } from '@core/constants';
import { environment } from '@envs/environment';
import { ApiResponse, ILogin } from '@nex-house/interfaces';
import { UserModel } from '@nex-house/models';
import { tapResponse } from '@ngrx/operators';
import {
  patchState,
  signalStore,
  withComputed,
  withHooks,
  withMethods,
  withProps,
  withState,
} from '@ngrx/signals';
import { rxMethod } from '@ngrx/signals/rxjs-interop';
import { lastValueFrom, pipe, switchMap, tap } from 'rxjs';
import { AuthService } from './services';

interface AuthState {
  user: UserModel | undefined;
  token: string | null;
  recoveryToken: string | undefined;
  exp: number;
}

const initialState: AuthState = {
  user: undefined,
  token: localStorage.getItem(APP_CONSTANTS.TOKEN_STORAGE_KEY),
  recoveryToken: undefined,
  exp: (() => {
    const cExp = localStorage.getItem(APP_CONSTANTS.TOKEN_EXP);
    if (!cExp) return 0;
    return Number(cExp);
  })(),
};

export const AuthStore = signalStore(
  { providedIn: 'root' },
  withState(initialState),
  withDevtools('auth'),
  withReset(),
  withCallState(),
  withProps(() => ({
    _authService: inject(AuthService),
  })),
  withComputed(({ user, token }) => ({
    isAuthenticated: computed(() => !!token() && !!user()),
    userRole: computed(() => user()?.role ?? null),
  })),
  withMethods((store) => ({
    login: async (dto: ILogin): Promise<boolean> => {
      patchState(store, setLoading());
      try {
        const res = await lastValueFrom(store._authService.login(dto));

        localStorage.setItem(APP_CONSTANTS.TOKEN_STORAGE_KEY, res.data.token);
        localStorage.setItem(APP_CONSTANTS.TOKEN_EXP, res.data.exp.toString());
        patchState(
          store,
          {
            token: res.data.token,
            user: res.data.user,
            exp: res.data.exp,
          },
          setLoaded(),
        );
        return true;
      } catch (error) {
        console.log('error', error);
        patchState(store, setError(error));
        return false;
      }
    },
    passRecovery: async (email: string): Promise<string> => {
      patchState(store, setLoading());
      try {
        const res = await lastValueFrom(
          store._authService.passwordRecovery(email),
        );

        patchState(store, setLoaded());

        if (environment.production) {
          return '';
        }

        return res.data;
      } catch (error) {
        console.log('error', error);
        patchState(store, setError(error));
        return '';
      }
    },
    validateCode: async (code: string): Promise<boolean> => {
      patchState(store, setLoading());
      try {
        const res = await lastValueFrom(store._authService.validateCode(code));

        patchState(store, { recoveryToken: res.data }, setLoaded());

        return true;
      } catch (error) {
        console.log('error', error);
        patchState(store, setError(error));
        return false;
      }
    },
    setNewPassword: async (newPassword: string) => {
      patchState(store, setLoading());
      try {
        const res = await lastValueFrom(
          store._authService.newPassword(store.recoveryToken()!, newPassword),
        );

        localStorage.setItem(APP_CONSTANTS.TOKEN_STORAGE_KEY, res.data.token);
        localStorage.setItem(APP_CONSTANTS.TOKEN_EXP, res.data.exp.toString());
        patchState(
          store,
          {
            token: res.data.token,
            user: res.data.user,
            exp: res.data.exp,
            recoveryToken: undefined,
          },
          setLoaded(),
        );
        return true;
      } catch (error) {
        console.log('error', error);
        patchState(store, setError(error));
        return false;
      }
    },
    me: rxMethod<void>(
      pipe(
        tap(() => patchState(store, { callState: 'loading' })),
        switchMap(() =>
          store._authService.me().pipe(
            tapResponse({
              next: (res: ApiResponse<UserModel>) => {
                patchState(
                  store,
                  {
                    user: res.data,
                  },
                  setLoaded(),
                );
              },
              error: (err: any) => {
                const errorMessage = err.error?.message || 'Identity failed';
                patchState(store, { callState: { error: errorMessage } });
              },
            }),
          ),
        ),
      ),
    ),
    logout() {
      localStorage.clear();
      localStorage.removeItem(APP_CONSTANTS.TOKEN_STORAGE_KEY);
      localStorage.removeItem(APP_CONSTANTS.TOKEN_EXP);
      store.resetState();
    },
  })),

  withHooks((store) => {
    return {
      onInit: (): void => {
        effect(() => {
          const cToken = store.token();
          const cUser = store.user();
          if (cToken && !cUser) {
            store.me();
          }
        });
      },
    };
  }),
);

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
} from '@angular/core';
import { AvatarModule } from 'primeng/avatar';
import { AvatarGroupModule } from 'primeng/avatargroup';
import { TooltipModule } from 'primeng/tooltip';

interface AvatarItem {
  label: string;
  fullLabel: string;
  color: string;
}

@Component({
  selector: 'app-user-avatar-group',
  imports: [AvatarModule, AvatarGroupModule, TooltipModule],
  templateUrl: './user-avatar-group.html',
  styleUrl: './user-avatar-group.css',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class UserAvatarGroup {
  text() {
    throw new Error('Method not implemented.');
  }
  private readonly palette = [
    '#ece9fc',
    '#dee9fc',
    '#dff7e9',
    '#fcf1e3',
    '#fce4ec',
    '#e0f7fa',
    '#f3e5f5',
    '#fff9c4',
    '#efebe9',
    '#f1f8e9',
  ];

  list = input<string[]>();

  avatars = computed<AvatarItem[]>(() => {
    const cList = this.list();

    if (!cList) return [];

    return cList.map((text) => {
      const result: AvatarItem = {
        label: 'N/A',
        fullLabel: 'N/A',
        color: this.palette[0],
      };

      if (!text || text === '') return result;

      result.fullLabel = text;

      let r = '';

      const textArray = text.split(' ');
      textArray.forEach((f) => (r += f[0]));

      result.label = r.toUpperCase();

      let hash = 0;
      for (let i = 0; i < text.length; i++) {
        hash = text.charCodeAt(i) + ((hash << 5) - hash);
      }
      const index = Math.abs(hash) % this.palette.length;
      result.color = this.palette[index];

      return result;
    });
  });
}

import { inject, Injectable, signal } from '@angular/core';
import { NavigationEnd, Router } from '@angular/router';
import { BREADCRUMB_MAP } from '@core/configs/breadcrumb.config';
import { filter } from 'rxjs';

export interface Breadcrumb {
  label: string;
  url: string;
}

@Injectable({ providedIn: 'root' })
export class BreadcrumbService {
  private router = inject(Router);
  readonly breadcrumbs = signal<Breadcrumb[]>([]);

  constructor() {
    this.router.events
      .pipe(filter((event) => event instanceof NavigationEnd))
      .subscribe(() => this.updateBreadcrumbs());

    this.updateBreadcrumbs(); // Carga inicial
  }

  private updateBreadcrumbs() {
    const url = this.router.url.split('?')[0];
    const segments = url.split('/').filter((s) => s !== '');

    const crumbs: Breadcrumb[] = [];
    let currentPath = '';

    segments.forEach((segment) => {
      currentPath += `/${segment}`;

      // Si el segmento es un UUID/ID, podrías manejarlo aquí.
      // Por ahora, usamos el mapa o el nombre tal cual.
      // const label = BREADCRUMB_MAP[segment] || segment;
      //
      // crumbs.push({ label, url: currentPath });
      let label = BREADCRUMB_MAP[segment];

      if (!label) {
        // Si el segmento es un UUID o un número largo, es un ID
        const isId = /^[0-9a-fA-F-]+$/.test(segment) || !isNaN(Number(segment));
        label = isId ? 'Detalles' : segment;
      }

      crumbs.push({ label, url: currentPath });
    });

    this.breadcrumbs.set(crumbs);
  }
}

import {
  setError,
  setLoaded,
  setLoading,
  withCallState,
  withDevtools,
  withReset,
} from '@angular-architects/ngrx-toolkit';
import { effect, inject } from '@angular/core';
import { AuthStore } from '@features/auth';
import { NeighborhoodService } from '@features/neighborhoods/services';
import { NeighborhoodModel } from '@nex-house/models';
import { tapResponse } from '@ngrx/operators';
import {
  patchState,
  signalStore,
  withHooks,
  withMethods,
  withProps,
  withState,
} from '@ngrx/signals';
import { rxMethod } from '@ngrx/signals/rxjs-interop';
import { pipe, switchMap, tap } from 'rxjs';

interface contextState {
  selectedId: string | null;
  neighborhood: NeighborhoodModel | undefined;
}

const initialState: contextState = {
  selectedId: null,
  neighborhood: undefined,
};

export const ContextStore = signalStore(
  { providedIn: 'root' },
  withDevtools('context'),
  withReset(),
  withCallState(),
  withState(initialState),
  withProps(() => ({
    _neighService: inject(NeighborhoodService),
  })),
  withMethods((store) => ({
    setNeighborhoodId(id: string | null) {
      patchState(store, { selectedId: id });
    },
    removeNeighborhood() {
      patchState(store, { neighborhood: undefined }, setLoaded());
    },
    getNeighborhood: rxMethod<void>(
      pipe(
        tap(() => patchState(store, setLoading())),
        switchMap(() => {
          const nId = store.selectedId();
          if (!nId) return [];

          return store._neighService.getById(nId).pipe(
            tapResponse({
              next: (response) =>
                patchState(store, { neighborhood: response.data }, setLoaded()),
              error: (err: Error) => patchState(store, setError(err)),
            }),
          );
        }),
      ),
    ),
  })),

  withHooks((store) => {
    const authStore = inject(AuthStore);
    return {
      onInit: (): void => {
        effect(() => {
          const cSelectedId = store.selectedId();
          const cNeigh = store.neighborhood();

          if (!cSelectedId) {
            store.removeNeighborhood();
            return;
          }

          if (!cNeigh) {
            store.getNeighborhood();
          }
        });

        effect(() => {
          const isAuth = authStore.isAuthenticated();

          if (!isAuth) {
            store.resetState();
            return;
          }
        });
      },
    };
  }),
);

import {
  setError,
  setLoaded,
  setLoading,
  withCallState,
  withReset,
} from '@angular-architects/ngrx-toolkit';
import { effect, inject } from '@angular/core';
import { AuthStore } from '@features/auth';
import {
  ApiPaginationMeta,
  Search,
  SearchCharges,
} from '@nex-house/interfaces';
import {
  ChargeCancelModel,
  ChargeConfirmModel,
  ChargeModel,
  ChargeSummaryModel,
} from '@nex-house/models';
import { tapResponse } from '@ngrx/operators';
import {
  patchState,
  signalStoreFeature,
  type,
  withHooks,
  withMethods,
  withProps,
  withState,
} from '@ngrx/signals';
import {
  entityConfig,
  setAllEntities,
  updateEntity,
  withEntities,
} from '@ngrx/signals/entities';
import { rxMethod } from '@ngrx/signals/rxjs-interop';
import { ContextStore } from '@stores/context.store';
import { lastValueFrom, pipe, switchMap, tap } from 'rxjs';
import { ChargesService } from '../services';

const config = entityConfig({
  entity: type<ChargeModel>(),
  collection: 'charges',
  selectId: (charge: ChargeModel) => charge.publicId,
});

interface FeeScheduleState {
  chargesSummary: ChargeSummaryModel | undefined;
  chargesFilters: Search | undefined;
  chargesPagination: ApiPaginationMeta | undefined;
}
const initialState: FeeScheduleState = {
  chargesSummary: undefined,
  chargesFilters: undefined,
  chargesPagination: undefined,
};

export function withChargeFeature() {
  return signalStoreFeature(
    withState(initialState),
    withEntities(config),
    withReset(),
    withCallState(),
    withProps(() => ({
      _contextStore: inject(ContextStore),
      _chargesService: inject(ChargesService),
    })),
    withMethods((store) => ({
      chargesLoadAll: rxMethod<SearchCharges>(
        pipe(
          tap(() => patchState(store, setLoading())),
          switchMap((params) => {
            const nId = store._contextStore.selectedId();
            if (!nId) return [];

            return store._chargesService.getAll(nId, params).pipe(
              tapResponse({
                next: (response) =>
                  patchState(
                    store,
                    setAllEntities(response.data, config),
                    {
                      chargesFilters: params,
                      chargesPagination: response.meta,
                    },
                    setLoaded(),
                  ),
                error: (err: Error) => patchState(store, setError(err)),
              }),
            );
          }),
        ),
      ),
      chargesLoadSummary: rxMethod<SearchCharges>(
        pipe(
          tap(() => patchState(store, setLoading())),
          switchMap((params) => {
            const nId = store._contextStore.selectedId();
            if (!nId) return [];

            return store._chargesService.getSummary(nId, params).pipe(
              tapResponse({
                next: (response) =>
                  patchState(
                    store,
                    { chargesSummary: response.data },
                    setLoaded(),
                  ),
                error: (err: Error) => patchState(store, setError(err)),
              }),
            );
          }),
        ),
      ),
      confirm: async (publicId: string, dto: ChargeConfirmModel) => {
        const nId = store._contextStore.selectedId();
        if (!nId) return false;

        patchState(store, setLoading());
        try {
          const response = await lastValueFrom(
            store._chargesService.confirm(publicId, nId, dto),
          );

          patchState(
            store,
            updateEntity({ id: publicId, changes: response.data }, config),
            setLoaded(),
          );
          return true;
        } catch (error) {
          patchState(store, setError(error));
          return false;
        }
      },

      cancel: async (publicId: string, dto: ChargeCancelModel) => {
        const nId = store._contextStore.selectedId();
        if (!nId) return false;

        patchState(store, setLoading());
        try {
          const response = await lastValueFrom(
            store._chargesService.cancel(publicId, nId, dto),
          );

          patchState(
            store,
            updateEntity({ id: publicId, changes: response.data }, config),
            setLoaded(),
          );
          return true;
        } catch (error) {
          patchState(store, setError(error));
          return false;
        }
      },
    })),
    withHooks((store) => {
      const authStore = inject(AuthStore);
      return {
        onInit: (): void => {
          effect(() => {
            const isAuth = authStore.isAuthenticated();
            if (!isAuth) {
              store.resetState();
            }
          });
        },
      };
    }),
  );
}

import {
  setError,
  setLoaded,
  setLoading,
  withCallState,
  withReset,
} from '@angular-architects/ngrx-toolkit';
import { computed, effect, inject } from '@angular/core';
import { AuthStore } from '@features/auth';
import {
  ApiPaginationMeta,
  ICreateFeeSchedule,
  Search,
} from '@nex-house/interfaces';
import { FeeScheduleModel } from '@nex-house/models';
import { tapResponse } from '@ngrx/operators';
import {
  patchState,
  signalStoreFeature,
  type,
  withComputed,
  withHooks,
  withMethods,
  withProps,
  withState,
} from '@ngrx/signals';
import {
  addEntity,
  entityConfig,
  setAllEntities,
  withEntities,
} from '@ngrx/signals/entities';
import { rxMethod } from '@ngrx/signals/rxjs-interop';
import { ContextStore } from '@stores/context.store';
import { lastValueFrom, pipe, switchMap, tap } from 'rxjs';
import { FeeScheduleService } from '../services';

const config = entityConfig({
  entity: type<FeeScheduleModel>(),
  collection: 'feeSchedules',
  selectId: (fee: FeeScheduleModel) => fee.publicId,
});

interface FeeScheduleState {
  feesFilters: Search | undefined;
  feesSchedulePagination: ApiPaginationMeta | undefined;
}
const initialState: FeeScheduleState = {
  feesFilters: undefined,
  feesSchedulePagination: undefined,
};

export function withFeeScheduleFeature() {
  return signalStoreFeature(
    withState(initialState),
    withEntities(config),
    withCallState({ collection: 'feeSchedules' }),
    withReset(),
    withProps(() => ({
      _contextStore: inject(ContextStore),
      _feeScheduleService: inject(FeeScheduleService),
    })),
    withComputed((store) => ({
      feeScheduleExists: computed(() => {
        if (store.feeSchedulesLoading()) {
          return false;
        }
        return (store.feesSchedulePagination()?.total || 0) > 0;
      }),
    })),
    withMethods((store) => ({
      feeScheduleLoadAll: rxMethod<Search>(
        pipe(
          tap(() => patchState(store, setLoading('feeSchedules'))),
          switchMap((params) => {
            const nId = store._contextStore.selectedId();
            if (!nId) {
              patchState(store, setLoaded('feeSchedules'));
              return [];
            }

            return store._feeScheduleService.getAll(nId, params).pipe(
              tapResponse({
                next: (response) =>
                  patchState(
                    store,
                    setAllEntities(response.data, config),
                    {
                      feesFilters: params,
                      feesSchedulePagination: response.meta,
                    },
                    setLoaded('feeSchedules'),
                  ),
                error: (err: Error) =>
                  patchState(store, setError(err, 'feeSchedules')),
              }),
            );
          }),
        ),
      ),
    })),
    withMethods((store) => ({
      feeScheduleCreate: async (dto: ICreateFeeSchedule): Promise<boolean> => {
        const nId = store._contextStore.selectedId();
        if (!nId) return false;

        patchState(store, setLoading('feeSchedules'));
        try {
          const response = await lastValueFrom(
            store._feeScheduleService.create(nId, dto),
          );
          patchState(
            store,
            addEntity(response.data, config),
            setLoaded('feeSchedules'),
          );
          store.feeScheduleLoadAll(store.feesFilters()!);
          return true;
        } catch (err) {
          patchState(store, setError(err, 'feeSchedules'));
          return false;
        }
      },
    })),
    withHooks((store) => {
      const authStore = inject(AuthStore);
      return {
        onInit: (): void => {
          effect(() => {
            const isAuth = authStore.isAuthenticated();

            if (!isAuth) {
              store.resetState();
              return;
            }

            if (!store.feesSchedulePagination()) {
              store.feeScheduleLoadAll({
                first: 0,
                rows: 10,
              });
            }
          });
        },
      };
    }),
  );
}

import { HttpErrorResponse } from '@angular/common/http';
import { ApiResponse } from '@nex-house/interfaces';

export interface FormattedError {
  message: string;
  statusCode?: number;
  originalError?: any;
  translationKey?: string; // Para futuras traducciones
}

export function formatError(error: any): FormattedError {
  let message = 'Ocurrió un error inesperado. Por favor, inténtalo de nuevo.';
  let statusCode: number | undefined;
  let translationKey = 'errors.unexpected';

  if (error instanceof HttpErrorResponse) {
    statusCode = error.status;
    if (error.error instanceof ErrorEvent) {
      // Error de red o del cliente (ej. error en el script)
      message = `Error de red: ${error.error.message}`;
      translationKey = 'errors.network';
    } else if (error.status === 0) {
      // El backend no responde o el usuario está sin conexión
      message =
        'No se pudo conectar al servidor. Por favor, verifica tu conexión a internet.';
      translationKey = 'errors.noConnection';
    } else if (error.error && typeof error.error === 'object') {
      // Error de la API con una estructura de respuesta específica (ej. ApiResponse)
      const apiError = error.error as ApiResponse<any>;
      if (apiError.message) {
        message = apiError.message;
        translationKey = `errors.api.${statusCode}`; // O una clave más genérica si no hay una específica
      } else if (typeof error.error === 'string') {
        // A veces el backend devuelve un string puro en error.error
        message = error.error;
        translationKey = `errors.api.${statusCode}`;
      } else {
        // Fallback para errores de servidor con estructura desconocida
        message = `Error del servidor (Código: ${statusCode}): ${error.statusText || 'Error desconocido'}.`;
        translationKey = `errors.server.${statusCode}`;
      }
    } else {
      // Otros errores HTTP desconocidos
      message = `Error en la solicitud (Código: ${statusCode}): ${error.message || error.statusText || 'Error desconocido'}.`;
      translationKey = `errors.http.${statusCode}`;
    }
  } else if (
    error &&
    typeof error === 'object' &&
    'message' in error &&
    typeof error.message === 'string' &&
    'statusCode' in error
  ) {
    // Si el error es directamente un objeto que cumple nuestra ApiResponse
    const apiError = error as ApiResponse<any>;
    statusCode = apiError.statusCode;
    if (statusCode && statusCode >= 400 && statusCode < 600) {
      message = apiError.message;
      translationKey = `errors.api.${statusCode}`;
    }
  } else if (error instanceof Error) {
    // Errores de JavaScript genéricos
    message = `Error de la aplicación: ${error.message}`;
    translationKey = 'errors.application';
  }

  // Opcional: Loguear el error original para depuración
  console.error('Error original interceptado:', error);

  return {
    message,
    statusCode,
    originalError: error,
    translationKey,
  };
}

import { FormControl } from '@angular/forms';

export interface INeighborhoodsForm {
