apps/web/src/app/_core/interceptors/auth.defaultValue:
(req, next) => {
  const token = localStorage.getItem(APP_CONSTANTS.TOKEN_STORAGE_KEY);

  if (token) {
    const clonedReq = req.clone({
      setHeaders: {
        Authorization: `Bearer ${token}`,
      },
    });
    return next(clonedReq);
  }
  return next(req);
}

